/*
** Parser State Cloning for Fork-Resolve Disambiguation
**
** Implements deep-copy of parser state to enable forking.  See
** include/parser_fork.h for the public API documentation.
**
** Key design decisions:
**
** 1. The yyParser struct is grammar-specific (generated by Lime), so
**    this module treats it as an opaque byte buffer with known field
**    offsets.  The caller passes layout parameters (sizeof, offsetof)
**    that are compile-time constants in the generated parser.
**
** 2. The parser stack may live in one of two places:
**    (a) Inline: yystack points to yystk0[] (the fixed-size array
**        embedded in yyParser).  This is the initial state.
**    (b) Heap: yystack points to a realloc'd buffer when the stack
**        grew beyond YYSTACKDEPTH.
**    Cloning handles both cases, always producing a clone whose stack
**    is heap-allocated (for simplicity and to avoid sizing constraints).
**
** 3. Immutable grammar tables (yy_action[], yy_lookahead[], etc.) are
**    shared through the ParserSnapshot, which is reference-counted.
**    Cloning acquires a reference to the snapshot rather than copying
**    the tables.
**
** 4. Semantic values (YYMINORTYPE) on the stack are memcpy'd.  This
**    works correctly for POD types and pointer-sized tokens.  If a
**    grammar uses heap-allocated semantic values with ownership
**    semantics, the caller must ensure the values are either shared
**    (with appropriate refcounting) or deep-copied after cloning.
*/
#include "parser_fork.h"
#include "snapshot.h"

#include <stdlib.h>
#include <string.h>
#include <stdatomic.h>

/* ================================================================== */
/*  Fork ID generation                                                 */
/* ================================================================== */

static atomic_uint_fast64_t g_next_fork_id = 1;

uint64_t parser_fork_next_id(void) {
    return atomic_fetch_add_explicit(&g_next_fork_id, 1,
                                     memory_order_relaxed);
}

/* ================================================================== */
/*  Internal helpers                                                   */
/* ================================================================== */

/*
** Read a pointer-sized field from a byte buffer at the given offset.
*/
static inline void *read_ptr(const void *base, size_t offset) {
    void *val;
    memcpy(&val, (const char *)base + offset, sizeof(void *));
    return val;
}

/*
** Write a pointer-sized field into a byte buffer at the given offset.
*/
static inline void write_ptr(void *base, size_t offset, void *val) {
    memcpy((char *)base + offset, &val, sizeof(void *));
}

/* ================================================================== */
/*  Cloning implementation                                             */
/* ================================================================== */

bool clone_parser_state(
    const void *parser,
    size_t parser_size,
    size_t stack_entry_size,
    size_t inline_stack_offset,
    uint32_t inline_stack_count,
    size_t stack_field_offset,
    size_t tos_field_offset,
    size_t stack_end_offset,
    ClonedParserState *out)
{
    if (parser == NULL || out == NULL || parser_size == 0 ||
        stack_entry_size == 0) {
        return false;
    }

    /* inline_stack_count describes the capacity of the source parser's
    ** inline yystk0[] buffer.  inline_stack_offset points to that buffer
    ** within the parser struct.  The clone always heap-allocates its
    ** stack (see Step 2 below), so we don't consume these values here;
    ** they remain part of the public API for symmetry with fork_parser()
    ** and potential future use (e.g. sizing heuristics). */
    (void)inline_stack_offset;
    (void)inline_stack_count;

    memset(out, 0, sizeof(*out));

    /* Read the source parser's stack pointers. */
    const void *src_stack = read_ptr(parser, stack_field_offset);
    const void *src_tos = read_ptr(parser, tos_field_offset);
    const void *src_stack_end = read_ptr(parser, stack_end_offset);

    if (src_stack == NULL || src_tos == NULL || src_stack_end == NULL) {
        return false;
    }

    /* Compute stack metrics. */
    ptrdiff_t tos_index =
        ((const char *)src_tos - (const char *)src_stack)
        / (ptrdiff_t)stack_entry_size;
    ptrdiff_t total_capacity =
        ((const char *)src_stack_end - (const char *)src_stack)
        / (ptrdiff_t)stack_entry_size + 1;

    if (tos_index < 0 || total_capacity <= 0) {
        return false;
    }

    uint32_t depth = (uint32_t)(tos_index + 1);  /* entries 0..tos inclusive */
    uint32_t capacity = (uint32_t)total_capacity;

    /* Step 1: Deep copy the yyParser struct. */
    void *clone = malloc(parser_size);
    if (clone == NULL) {
        return false;
    }
    memcpy(clone, parser, parser_size);

    /*
    ** Step 2: Clone the stack.
    **
    ** We always allocate a separate heap buffer for the cloned stack,
    ** even if the original was using the inline yystk0[].  This
    ** simplifies lifecycle management: the cloned stack is always
    ** freed with free(), and we don't need to worry about the inline
    ** buffer being undersized for future growth.
    */
    size_t stack_bytes = (size_t)capacity * stack_entry_size;
    void *new_stack = malloc(stack_bytes);
    if (new_stack == NULL) {
        free(clone);
        return false;
    }

    /* Copy all stack entries up to and including tos. */
    size_t used_bytes = (size_t)depth * stack_entry_size;
    memcpy(new_stack, src_stack, used_bytes);

    /* Zero the unused portion (defensive). */
    if (stack_bytes > used_bytes) {
        memset((char *)new_stack + used_bytes, 0, stack_bytes - used_bytes);
    }

    /* Step 3: Fix up pointers inside the cloned yyParser.
    **
    ** yystack -> new_stack
    ** yytos   -> new_stack + (tos_index * entry_size)
    ** yystackEnd -> new_stack + ((capacity - 1) * entry_size)
    */
    write_ptr(clone, stack_field_offset, new_stack);

    void *new_tos = (char *)new_stack +
                    (size_t)tos_index * stack_entry_size;
    write_ptr(clone, tos_field_offset, new_tos);

    void *new_stack_end = (char *)new_stack +
                          (size_t)(capacity - 1) * stack_entry_size;
    write_ptr(clone, stack_end_offset, new_stack_end);

    /* Fill out the result. */
    out->state_data = clone;
    out->state_size = parser_size;
    out->stack_data = new_stack;
    out->stack_size = stack_bytes;
    out->stack_depth = depth;
    out->stack_capacity = capacity;
    out->stack_is_inline = false;  /* We always heap-allocate the clone */

    return true;
}

void cloned_parser_state_destroy(ClonedParserState *cloned) {
    if (cloned == NULL) return;

    /*
    ** Free the stack buffer first (it's separate from state_data
    ** because the clone never uses the inline yystk0[]).
    */
    if (!cloned->stack_is_inline && cloned->stack_data != NULL) {
        free(cloned->stack_data);
    }

    free(cloned->state_data);
    memset(cloned, 0, sizeof(*cloned));
}

/* ================================================================== */
/*  Fork lifecycle                                                     */
/* ================================================================== */

ParseFork *fork_parser(
    const void *parser,
    size_t parser_size,
    size_t stack_entry_size,
    size_t inline_stack_offset,
    uint32_t inline_stack_count,
    size_t stack_field_offset,
    size_t tos_field_offset,
    size_t stack_end_offset,
    struct ParserSnapshot *snapshot,
    int priority)
{
    if (parser == NULL) return NULL;

    ParseFork *fork = calloc(1, sizeof(ParseFork));
    if (fork == NULL) return NULL;

    /* Clone the parser state. */
    bool ok = clone_parser_state(
        parser, parser_size, stack_entry_size,
        inline_stack_offset, inline_stack_count,
        stack_field_offset, tos_field_offset, stack_end_offset,
        &fork->cloned_state);

    if (!ok) {
        free(fork);
        return NULL;
    }

    /* Acquire a reference to the snapshot. */
    fork->snapshot = snapshot_acquire(snapshot);

    fork->priority = priority;
    fork->status = FORK_PENDING;
    fork->semantic_result = NULL;
    fork->free_result = NULL;
    fork->tokens_consumed = 0;
    fork->error_count = 0;
    fork->fork_id = parser_fork_next_id();

    return fork;
}

void free_parse_fork(ParseFork *fork) {
    if (fork == NULL) return;

    /* Free semantic result. */
    if (fork->semantic_result != NULL) {
        if (fork->free_result != NULL) {
            fork->free_result(fork->semantic_result);
        } else {
            free(fork->semantic_result);
        }
        fork->semantic_result = NULL;
    }

    /* Release snapshot reference. */
    if (fork->snapshot != NULL) {
        snapshot_release(fork->snapshot);
        fork->snapshot = NULL;
    }

    /* Destroy cloned parser state. */
    cloned_parser_state_destroy(&fork->cloned_state);

    free(fork);
}

/* ================================================================== */
/*  Fork state access                                                  */
/* ================================================================== */

void *parse_fork_get_parser(ParseFork *fork) {
    if (fork == NULL) return NULL;
    return fork->cloned_state.state_data;
}

struct ParserSnapshot *parse_fork_get_snapshot(const ParseFork *fork) {
    if (fork == NULL) return NULL;
    return fork->snapshot;
}

void parse_fork_complete(ParseFork *fork, void *result,
                         void (*free_fn)(void *)) {
    if (fork == NULL) return;
    fork->status = FORK_COMPLETED;
    fork->semantic_result = result;
    fork->free_result = free_fn;
}

void parse_fork_fail(ParseFork *fork) {
    if (fork == NULL) return;
    fork->status = FORK_FAILED;
}

void parse_fork_abandon(ParseFork *fork) {
    if (fork == NULL) return;
    fork->status = FORK_ABANDONED;
}

/* ================================================================== */
/*  Fork set management                                                */
/* ================================================================== */

#define FORK_SET_INITIAL_CAPACITY 4

ParseForkSet *parse_fork_set_create(uint32_t max_forks) {
    ParseForkSet *set = calloc(1, sizeof(ParseForkSet));
    if (set == NULL) return NULL;

    uint32_t initial = FORK_SET_INITIAL_CAPACITY;
    if (max_forks > 0 && max_forks < initial) {
        initial = max_forks;
    }

    set->forks = calloc(initial, sizeof(ParseFork *));
    if (set->forks == NULL) {
        free(set);
        return NULL;
    }

    set->count = 0;
    set->capacity = initial;
    set->max_forks = max_forks;

    return set;
}

void parse_fork_set_destroy(ParseForkSet *set) {
    if (set == NULL) return;

    for (uint32_t i = 0; i < set->count; i++) {
        free_parse_fork(set->forks[i]);
    }

    free(set->forks);
    free(set);
}

bool parse_fork_set_add(ParseForkSet *set, ParseFork *fork) {
    if (set == NULL || fork == NULL) return false;

    /* Check capacity limit. */
    if (set->max_forks > 0 && set->count >= set->max_forks) {
        return false;
    }

    /* Grow the array if needed. */
    if (set->count >= set->capacity) {
        uint32_t new_cap = set->capacity * 2;
        if (new_cap < 8) new_cap = 8;
        if (set->max_forks > 0 && new_cap > set->max_forks) {
            new_cap = set->max_forks;
        }

        ParseFork **new_array = realloc(set->forks,
                                        new_cap * sizeof(ParseFork *));
        if (new_array == NULL) {
            return false;
        }
        set->forks = new_array;
        set->capacity = new_cap;
    }

    set->forks[set->count++] = fork;
    return true;
}

uint32_t parse_fork_set_prune(ParseForkSet *set) {
    if (set == NULL || set->count == 0) return 0;

    uint32_t pruned = 0;
    uint32_t write = 0;

    for (uint32_t read = 0; read < set->count; read++) {
        ParseFork *f = set->forks[read];
        if (f->status == FORK_FAILED || f->status == FORK_ABANDONED) {
            free_parse_fork(f);
            pruned++;
        } else {
            set->forks[write++] = f;
        }
    }

    set->count = write;
    return pruned;
}

ParseFork *parse_fork_set_best(const ParseForkSet *set) {
    if (set == NULL || set->count == 0) return NULL;

    ParseFork *best = NULL;

    for (uint32_t i = 0; i < set->count; i++) {
        ParseFork *f = set->forks[i];
        if (f->status != FORK_COMPLETED) continue;

        if (best == NULL || f->priority < best->priority) {
            best = f;
        } else if (f->priority == best->priority) {
            /* Tie-break: fewer errors wins, then fewer tokens consumed. */
            if (f->error_count < best->error_count) {
                best = f;
            } else if (f->error_count == best->error_count &&
                       f->tokens_consumed < best->tokens_consumed) {
                best = f;
            }
        }
    }

    return best;
}

uint32_t parse_fork_set_active_count(const ParseForkSet *set) {
    if (set == NULL) return 0;

    uint32_t active = 0;
    for (uint32_t i = 0; i < set->count; i++) {
        ParseForkStatus s = set->forks[i]->status;
        if (s == FORK_PENDING || s == FORK_RUNNING) {
            active++;
        }
    }

    return active;
}
